fun <- function(x, r){
	if(r > 0){
		m <- length(x) %/% r
		y <- numeric(m)
		for(i in seq_len(m)){
			y[i] <- sum(x[((i - 1)*r + 1):(i*r)])
		}
		y
	}else{
		NULL
	}
}

